import{_ as e,o as t,c as r,a4 as o}from"./chunks/framework.BDOgl-CJ.js";const p="/photo.jpg",_=JSON.parse('{"title":"关于我","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1779249089000}'),h={name:"about.md"};function l(n,a,i,s,d,u){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="关于我" tabindex="-1">关于我 <a class="header-anchor" href="#关于我" aria-label="Permalink to &quot;关于我&quot;">​</a></h1><div style="text-align:center;margin:24px 0;"><img src="'+p+'" alt="个人照片" style="width:260px;border-radius:12px;"></div><p>32 岁。北京。暂时一个人。</p><hr><h2 id="平时在干嘛" tabindex="-1">平时在干嘛 <a class="header-anchor" href="#平时在干嘛" aria-label="Permalink to &quot;平时在干嘛&quot;">​</a></h2><p>打游戏、跑步、找朋友玩。</p><p>没有特别宏大的安排。周末如果没事，可能在打游戏，可能在公园跑步，也可能在和朋友瞎逛。不太需要把每一天都填满，能在该做的事情上认真一点，剩下的时间就让它自然流动。</p><p>跑步是真的喜欢，不是为了健康才去跑。跑起来的时候脑子会放空，什么都不用想，就是腿在动、风在吹，挺好的。</p><hr><h2 id="aquaflow-是怎么回事" tabindex="-1">Aquaflow 是怎么回事 <a class="header-anchor" href="#aquaflow-是怎么回事" aria-label="Permalink to &quot;Aquaflow 是怎么回事&quot;">​</a></h2><p><a href="https://www.aquaflow777.com/" target="_blank" rel="noreferrer">Aquaflow</a> 是我在做的一个公益行动——在北京的公园和街区徒步，给环卫工人、建筑工人、保安这些人送水。</p><p>第一次做的时候非常开心。</p><p>不是那种&quot;我帮了人好有成就感&quot;的开心，是一种很简单的、走在路上把水递出去的时候，对方接过来喝了一口，这件事就完成了，这个感觉很踏实。</p><p>之后就一直在做。不是因为使命感，是因为这件事做起来真的让我觉得值。</p><hr><h2 id="一个人也还行" tabindex="-1">一个人也还行 <a class="header-anchor" href="#一个人也还行" aria-label="Permalink to &quot;一个人也还行&quot;">​</a></h2><p>有时候会被问到结婚的事，偶尔有点压力，但也不是特别焦虑。</p><p>现在一个人的状态，暂时是 OK 的。不是在等什么，也不是在逃什么，就是随缘。</p><p>感情这件事如果勉强，双方都累。</p><hr><h2 id="_32-岁和-20-岁有什么区别" tabindex="-1">32 岁和 20 岁有什么区别 <a class="header-anchor" href="#_32-岁和-20-岁有什么区别" aria-label="Permalink to &quot;32 岁和 20 岁有什么区别&quot;">​</a></h2><p>老实说，感觉没太大区别。</p><p>心态上可能更稳一点，不会为了很小的事情焦虑，也不太容易被&quot;你应该在这个年纪做什么&quot;这种话绕进去。</p><p>最重要的事情只有一件：<strong>保持心态健康积极，不让什么东西来催着自己。</strong></p><p>年龄不是特别好用的标尺，状态才是。</p><hr><h2 id="在和自己较劲的事" tabindex="-1">在和自己较劲的事 <a class="header-anchor" href="#在和自己较劲的事" aria-label="Permalink to &quot;在和自己较劲的事&quot;">​</a></h2><p>欲望这件事挺难的，不只是情欲，是各种层面的冲动——想立刻得到某个东西、想逃避某个不舒服的状态。</p><p>我在慢慢练习的是：让冲动先来，观察它，再决定要不要跟着走。不是压制，是选择。</p><p>有时候能做到，有时候做不到。</p><hr><h2 id="工程是我的另一面" tabindex="-1">工程是我的另一面 <a class="header-anchor" href="#工程是我的另一面" aria-label="Permalink to &quot;工程是我的另一面&quot;">​</a></h2><p>我是做技术的，后端和全栈方向，用 Go / Python / Node.js。</p><p>这个站点就是我自己搭的，用来记东西、沉淀一些方法、偶尔写点思考。</p><p>技术对我来说不是终点，是一种把事情做清楚的方式。</p><p>GitHub：<a href="https://github.com/1sunzichen" target="_blank" rel="noreferrer">@1sunzichen</a></p>',36)])])}const f=e(h,[["render",l]]);export{_ as __pageData,f as default};
